/**
 * htmlParser.js
 * Parser robuste pour le builder RB Performance.
 *
 * Il gère 2 cas :
 * 1. HTML avec vraie structure DOM (.week-block, .seance-block, .exercise-item)
 * 2. HTML exporté / statique où les données doivent être reconstruites
 *    à partir des IDs du builder :
 *    - sn-s1_1
 *    - sd-s1_1
 *    - sf-s1_1
 *    - en-s1_1_e1
 *    - er-s1_1_e1
 *    - et-s1_1_e1
 *    - eri-s1_1_e1
 *    - ers-s1_1_e1
 *    - eg-s1_1_e1
 *    - egt-s1_1_e1
 *    - ev-s1_1_e1
 *    - eth-s1_1_e1
 */

function normalizeText(value, fallback = "") {
  const text = String(value ?? "").trim();
  return text || fallback;
}

function safeValue(el, fallback = "") {
  if (!el) return fallback;

  if (el.tagName === "SELECT") {
    const selectedOpt =
      el.querySelector("option[selected]") ||
      el.querySelector("option:checked") ||
      el.options?.[el.selectedIndex] ||
      el.querySelector("option");

    return (
      selectedOpt?.value ||
      selectedOpt?.textContent?.trim() ||
      fallback
    );
  }

  return (
    el.value ||
    el.getAttribute("value") ||
    el.textContent?.trim() ||
    fallback
  );
}

function parseReps(raw) {
  const cleaned = normalizeText(raw, "—");
  if (cleaned === "—") {
    return { sets: null, reps: "—" };
  }

  const match = cleaned.match(/^(\d+)\s*[xX×]\s*(.+)$/);
  if (match) {
    return {
      sets: parseInt(match[1], 10),
      reps: match[2].trim(),
    };
  }

  return {
    sets: null,
    reps: cleaned,
  };
}

function getMeta(doc) {
  return {
    programName: normalizeText(
      safeValue(doc.getElementById("prog-name"), "Programme"),
      "Programme"
    ),
    clientName: normalizeText(
      safeValue(doc.getElementById("client-name"), ""),
      ""
    ),
    progDuration: normalizeText(
      safeValue(doc.getElementById("prog-duration"), ""),
      ""
    ),
    progTagline: normalizeText(
      safeValue(doc.getElementById("prog-tagline"), ""),
      ""
    ),
    progObj: normalizeText(
      safeValue(doc.getElementById("prog-obj"), ""),
      ""
    ),
  };
}

/* =========================
   MODE 1 : parse DOM direct
========================= */

function parseFromDomStructure(doc) {
  const weekBlocks = [...doc.querySelectorAll(".week-block")];
  if (!weekBlocks.length) {
    return [];
  }

  const weeks = [];

  weekBlocks.forEach((weekEl, weekIdx) => {
    const weekId = weekEl.id || "";
    const weekMatch = weekId.match(/^week-(\d+)$/i);
    const weekNumber = weekMatch ? parseInt(weekMatch[1], 10) : weekIdx + 1;

    const sessions = [];
    const seanceBlocks = [...weekEl.querySelectorAll(".seance-block")];

    seanceBlocks.forEach((seanceEl, seanceIdx) => {
      const rawSeanceId = seanceEl.id || "";
      const seanceId = rawSeanceId.replace(/^seance-/, "");

      const sessionName = normalizeText(
        safeValue(doc.getElementById(`sn-${seanceId}`), `Séance ${seanceIdx + 1}`),
        `Séance ${seanceIdx + 1}`
      );

      const description = normalizeText(
        safeValue(doc.getElementById(`sd-${seanceId}`), ""),
        ""
      );

      const finisher = normalizeText(
        safeValue(doc.getElementById(`sf-${seanceId}`), ""),
        ""
      );

      const exercises = [];
      const exerciseItems = [...seanceEl.querySelectorAll(".exercise-item")];

      exerciseItems.forEach((exEl, exIdx) => {
        const rawExId = exEl.id || "";
        const eid = rawExId.replace(/^ex-/, "");

        const exName = normalizeText(
          safeValue(doc.getElementById(`en-${eid}`), ""),
          ""
        );

        if (!exName) return;

        const repsRaw = normalizeText(
          safeValue(doc.getElementById(`er-${eid}`), "—"),
          "—"
        );
        const { sets, reps } = parseReps(repsRaw);

        exercises.push({
          id: eid || `s${weekNumber}_${seanceIdx + 1}_e${exIdx + 1}`,
          name: exName,
          sets: sets || 3,
          reps,
          tempo: normalizeText(safeValue(doc.getElementById(`et-${eid}`), "—"), "—"),
          rir: normalizeText(safeValue(doc.getElementById(`eri-${eid}`), "—"), "—"),
          rest: normalizeText(safeValue(doc.getElementById(`ers-${eid}`), "—"), "—"),
          group: normalizeText(safeValue(doc.getElementById(`eg-${eid}`), ""), "").toUpperCase(),
          groupType: normalizeText(safeValue(doc.getElementById(`egt-${eid}`), ""), ""),
          vidUrl: normalizeText(safeValue(doc.getElementById(`ev-${eid}`), ""), ""),
          thumbUrl: normalizeText(safeValue(doc.getElementById(`eth-${eid}`), ""), ""),
        });
      });

      if (sessionName || exercises.length) {
        sessions.push({
          id: seanceId || `s${weekNumber}_${seanceIdx + 1}`,
          weekNumber,
          sessionNumber: seanceIdx + 1,
          name: sessionName,
          description,
          finisher,
          exercises,
        });
      }
    });

    if (sessions.length) {
      weeks.push({ weekNumber, sessions });
    }
  });

  return weeks;
}

/* =========================
   MODE 2 : reconstruction par IDs
========================= */

function collectByIdPattern(doc) {
  const allWithId = [...doc.querySelectorAll("[id]")].map((el) => el.id);

  const seanceIds = new Set();
  const exerciseIds = new Set();

  for (const id of allWithId) {
    const seanceMatch = id.match(/^sn-(s\d+_\d+)$/i);
    if (seanceMatch) {
      seanceIds.add(seanceMatch[1]);
    }

    const exMatch = id.match(/^en-(s\d+_\d+_e\d+)$/i);
    if (exMatch) {
      exerciseIds.add(exMatch[1]);
    }
  }

  return {
    seanceIds: [...seanceIds],
    exerciseIds: [...exerciseIds],
  };
}

function parseFromIdPatterns(doc) {
  const { seanceIds, exerciseIds } = collectByIdPattern(doc);

  if (!seanceIds.length && !exerciseIds.length) {
    return [];
  }

  const weeksMap = new Map();

  // Préparer les séances
  seanceIds.forEach((sid) => {
    const m = sid.match(/^s(\d+)_(\d+)$/i);
    if (!m) return;

    const weekNumber = parseInt(m[1], 10);
    const sessionNumber = parseInt(m[2], 10);

    if (!weeksMap.has(weekNumber)) {
      weeksMap.set(weekNumber, {
        weekNumber,
        sessions: [],
      });
    }

    const week = weeksMap.get(weekNumber);

    week.sessions.push({
      id: sid,
      weekNumber,
      sessionNumber,
      name: normalizeText(
        safeValue(doc.getElementById(`sn-${sid}`), `Séance ${sessionNumber}`),
        `Séance ${sessionNumber}`
      ),
      description: normalizeText(
        safeValue(doc.getElementById(`sd-${sid}`), ""),
        ""
      ),
      finisher: normalizeText(
        safeValue(doc.getElementById(`sf-${sid}`), ""),
        ""
      ),
      exercises: [],
    });
  });

  // Trier les séances
  for (const week of weeksMap.values()) {
    week.sessions.sort((a, b) => a.sessionNumber - b.sessionNumber);
  }

  // Injecter les exercices
  exerciseIds.forEach((eid) => {
    const m = eid.match(/^s(\d+)_(\d+)_e(\d+)$/i);
    if (!m) return;

    const weekNumber = parseInt(m[1], 10);
    const sessionNumber = parseInt(m[2], 10);
    const exerciseNumber = parseInt(m[3], 10);

    const exName = normalizeText(
      safeValue(doc.getElementById(`en-${eid}`), ""),
      ""
    );

    if (!exName) return;

    if (!weeksMap.has(weekNumber)) {
      weeksMap.set(weekNumber, {
        weekNumber,
        sessions: [],
      });
    }

    const week = weeksMap.get(weekNumber);

    let session = week.sessions.find((s) => s.sessionNumber === sessionNumber);
    if (!session) {
      const sid = `s${weekNumber}_${sessionNumber}`;
      session = {
        id: sid,
        weekNumber,
        sessionNumber,
        name: normalizeText(
          safeValue(doc.getElementById(`sn-${sid}`), `Séance ${sessionNumber}`),
          `Séance ${sessionNumber}`
        ),
        description: normalizeText(
          safeValue(doc.getElementById(`sd-${sid}`), ""),
          ""
        ),
        finisher: normalizeText(
          safeValue(doc.getElementById(`sf-${sid}`), ""),
          ""
        ),
        exercises: [],
      };
      week.sessions.push(session);
    }

    const repsRaw = normalizeText(
      safeValue(doc.getElementById(`er-${eid}`), "—"),
      "—"
    );
    const { sets, reps } = parseReps(repsRaw);

    session.exercises.push({
      id: eid,
      exerciseNumber,
      name: exName,
      sets: sets || 3,
      reps,
      tempo: normalizeText(safeValue(doc.getElementById(`et-${eid}`), "—"), "—"),
      rir: normalizeText(safeValue(doc.getElementById(`eri-${eid}`), "—"), "—"),
      rest: normalizeText(safeValue(doc.getElementById(`ers-${eid}`), "—"), "—"),
      group: normalizeText(safeValue(doc.getElementById(`eg-${eid}`), ""), "").toUpperCase(),
      groupType: normalizeText(safeValue(doc.getElementById(`egt-${eid}`), ""), ""),
      vidUrl: normalizeText(safeValue(doc.getElementById(`ev-${eid}`), ""), ""),
      thumbUrl: normalizeText(safeValue(doc.getElementById(`eth-${eid}`), ""), ""),
    });
  });

  const weeks = [...weeksMap.values()]
    .map((week) => ({
      ...week,
      sessions: week.sessions
        .sort((a, b) => a.sessionNumber - b.sessionNumber)
        .map((session) => ({
          ...session,
          exercises: session.exercises.sort(
            (a, b) => (a.exerciseNumber || 0) - (b.exerciseNumber || 0)
          ),
        })),
    }))
    .sort((a, b) => a.weekNumber - b.weekNumber);

  return weeks;
}

/* =========================
   API publique
========================= */

export function parseHTMLProgram(htmlString) {
  const parser = new DOMParser();
  const doc = parser.parseFromString(htmlString, "text/html");

  const parserError = doc.querySelector("parsererror");
  if (parserError) {
    throw new Error("HTML invalide ou non lisible.");
  }

  const meta = getMeta(doc);

  let weeks = parseFromDomStructure(doc);

  // Si les week-block existent mais sont vides, ou absents, fallback par IDs
  if (!weeks.length) {
    weeks = parseFromIdPatterns(doc);
  }

  console.log("[htmlParser] meta:", meta);
  console.log("[htmlParser] weeks détectées:", weeks.length);
  console.log("[htmlParser] détail:", weeks);

  return {
    ...meta,
    weeks,
    totalWeeks: weeks.length,
    totalSessions: weeks.reduce((acc, w) => acc + w.sessions.length, 0),
  };
}

export function parseHTMLFile(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();

    reader.onload = (e) => {
      try {
        const htmlString = e.target?.result;
        const result = parseHTMLProgram(htmlString);
        resolve(result);
      } catch (err) {
        reject(err);
      }
    };

    reader.onerror = () => {
      reject(new Error("Impossible de lire le fichier HTML."));
    };

    reader.readAsText(file, "utf-8");
  });
}
